import{_ as e,o as a,c as r,ae as o}from"./chunks/framework.BGHOrOyn.js";const m=JSON.parse('{"title":"Hack Your Car With Wio Terminal and CAN Bus","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/guides/hackster.io/hack-your-car-with-wio-terminal-and-can-bus.md","filePath":"obd2/guides/hackster.io/hack-your-car-with-wio-terminal-and-can-bus.md"}'),i={name:"obd2/guides/hackster.io/hack-your-car-with-wio-terminal-and-can-bus.md"};function n(d,t,s,h,c,l){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="hack-your-car-with-wio-terminal-and-can-bus" tabindex="-1">Hack Your Car With Wio Terminal and CAN Bus <a class="header-anchor" href="#hack-your-car-with-wio-terminal-and-can-bus" aria-label="Permalink to &quot;Hack Your Car With Wio Terminal and CAN Bus&quot;">​</a></h1><p><a href="https://www.hackster.io/longan_labs/hack-your-car-with-wio-terminal-and-can-bus-c6ddf4" target="_blank" rel="noreferrer">https://www.hackster.io/longan_labs/hack-your-car-with-wio-terminal-and-can-bus-c6ddf4</a></p><p><a href="../../../.gitbook/assets/Eagle_File_Serial_CAN_Bus-master.zip">Eagle_File_Serial_CAN_Bus-master.zip</a></p><p><a href="../../../.gitbook/assets/OBD-II-Demo-x-Wio-Terminal-master%20(1).zip">OBD-II-Demo-x-Wio-Terminal-master (1).zip</a></p><p>Hack your car and read the cycling speed, rotation speed, oil temperature and other information, displayed on the Wio Terminal screen.</p><p><a href="https://www.hackster.io/projects?difficulty=intermediate" target="_blank" rel="noreferrer">Intermediate</a>Full instructions provided1,760<img src="https://hackster.imgix.net/uploads/attachments/1279245/_NWDIaPWC5C.blob?auto=compress%2Cformat&amp;w=900&amp;h=675&amp;fit=min" alt="Hack Your Car With Wio Terminal and CAN Bus"></p><h2 id="things-used-in-this-project" tabindex="-1">Things used in this project <a class="header-anchor" href="#things-used-in-this-project" aria-label="Permalink to &quot;Things used in this project&quot;">​</a></h2><table tabindex="0"><thead><tr><th><h4>Hardware components</h4></th><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td></td><td>75395a18632c4925826b92841002897c</td><td>×</td><td>1</td><td></td></tr><tr><td>OBD-II Serial CAN Bus Dev Kit</td><td></td><td></td><td></td><td></td></tr><tr><td>Important Note: This project needs the V1.3 version or later of Serial can bus module.</td><td></td><td></td><td></td><td></td></tr><tr><td><img src="https://hackster.imgix.net/uploads/attachments/1336801/2021-08-17_11_13_45_iktDtmkGww.png?auto=compress%2Cformat&amp;w=48&amp;h=48&amp;fit=fill&amp;bg=ffffff" alt="Wio Terminal"></td><td>01fcd22aef7d4bc6829c51df027141a9</td><td>×</td><td>1</td><td></td></tr><tr><td><a href="https://www.hackster.io/seeed/products/wio-terminal?ref=project-c6ddf4" target="_blank" rel="noreferrer">Seeed Studio Wio Terminal</a></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td>4c1fc6cea80a438396e4e8d1fceed664</td><td>×</td><td>1</td><td></td></tr><tr><td>Wio Terminal Chassis - Battery (650mAh)</td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td><h4>Hand tools and fabrication machines</h4></td><td></td><td></td><td></td><td></td></tr><tr><td><img src="https://hackster.imgix.net/uploads/image/file/79853/09507-01.jpg?auto=compress%2Cformat&amp;w=48&amp;h=48&amp;fit=fill&amp;bg=ffffff" alt="Soldering iron (generic)"></td><td>b202623f4f5d40e5bacce23a21689418</td><td></td><td></td><td></td></tr><tr><td>Soldering iron (generic)</td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td><img src="https://hackster.imgix.net/uploads/attachments/842592/4966285.jpg?auto=compress%2Cformat&amp;w=48&amp;h=48&amp;fit=fill&amp;bg=ffffff" alt="Solder Wire, Lead Free"></td><td>e63eb809bf4840f8a603084ce669002c</td><td></td><td></td><td></td></tr><tr><td>Solder Wire, Lead Free</td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="story" tabindex="-1">Story <a class="header-anchor" href="#story" aria-label="Permalink to &quot;Story&quot;">​</a></h3><p>If you have some understanding of CAN Bus and Arduino programming, and want to hack your car, then this tutorial can provide you with a solution.</p><p>As for why you want to hack your car, I don&#39;t know, but this is indeed an interesting thing.</p><p>This project mainly used the Serial CAN Bus Module by <a href="https://www.longan-labs.cc/" target="_blank" rel="noreferrer"><strong>Longan Labs</strong></a> and the Wio Terminal main control board by <a href="https://www.seeedstudio.com/" target="_blank" rel="noreferrer"><strong>Seeed Studio</strong></a>.</p><p>The <a href="https://www.longan-labs.cc/1030002.html" target="_blank" rel="noreferrer"><strong>OBD-II Serial CAN Bus Dev Kit</strong></a> is a CAN Bus control kit designed by Longan Labs. It uses UART to communicate with the single-chip microcomputer. It is compact and easy to use.</p><p>Wio Terminal comes from Seeedstuio, which is a development board with a screen that can be programmed with Arduino.</p><p>In this project, the following functions are mainly realized:</p><ul><li>Read the cycling speed, rotation speed and oil temperature and other information, displayed on the Wio Terminal screen</li></ul><p>If you want more date from the car, please refer to <a href="https://en.wikipedia.org/wiki/OBD-II_PIDs" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/OBD-II_PIDs</a></p><h4 id="step-1-principle-introduction" tabindex="-1">Step 1 : Principle Introduction <a href="#toc-step-1---principle-introduction-0" id="toc-step-1---principle-introduction-0"></a> <a class="header-anchor" href="#step-1-principle-introduction" aria-label="Permalink to &quot;Step 1 : Principle Introduction &lt;a href=&quot;#toc-step-1---principle-introduction-0&quot; id=&quot;toc-step-1---principle-introduction-0&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Almost all modern vehicles have an OBD-II interface, which is a bridge between the car and the outside world. We can get all the car information and control the car through the OBD-II interface.</p><p>And, it is a dangerous thing to control the car, you&#39;d better have a deep understanding of the OBD-II interface before proceeding. This article only reads some basic information from the car, so you can safely follow the steps provided in this tutorial.</p><h4 id="step-2-get-components-ready" tabindex="-1">Step 2 : Get Components Ready <a href="#toc-step-2---get-components-ready-1" id="toc-step-2---get-components-ready-1"></a> <a class="header-anchor" href="#step-2-get-components-ready" aria-label="Permalink to &quot;Step 2 : Get Components Ready &lt;a href=&quot;#toc-step-2---get-components-ready-1&quot; id=&quot;toc-step-2---get-components-ready-1&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li><a href="https://www.seeedstudio.com/Wio-Terminal-p-4509.html" target="_blank" rel="noreferrer">Wio Terminal</a></li><li><a href="https://www.seeedstudio.com/Wio-Terminal-p-4509.html" target="_blank" rel="noreferrer">Wio Terminal Battery Chassis</a></li></ul><p>Important Note: This project needs the V1.3 version or later of Serial can bus module.</p><h4 id="step-3-soldering" tabindex="-1">Step 3: Soldering <a href="#toc-step-3--soldering-2" id="toc-step-3--soldering-2"></a> <a class="header-anchor" href="#step-3-soldering" aria-label="Permalink to &quot;Step 3: Soldering &lt;a href=&quot;#toc-step-3--soldering-2&quot; id=&quot;toc-step-3--soldering-2&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://hackster.imgix.net/uploads/attachments/1279335/fvqepwkkf73rjkw_DYpbJIIcr0.jpeg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt="">1 / 3</p><p>This may be the most difficult step, if you have never used a soldering iron.</p><p>We need to solder the wire provided by OBD-II CAN-BUS Dev kit to an OBD-connector. You can look at the picture, we soldered the red wire to the 6pin of the connector, and the black wire to 14pin. When 6pin represents CANH, 14pin represents CANL.</p><h4 id="step-4-hardware-connection" tabindex="-1">Step 4: Hardware Connection <a href="#toc-step-4--hardware-connection-3" id="toc-step-4--hardware-connection-3"></a> <a class="header-anchor" href="#step-4-hardware-connection" aria-label="Permalink to &quot;Step 4: Hardware Connection &lt;a href=&quot;#toc-step-4--hardware-connection-3&quot; id=&quot;toc-step-4--hardware-connection-3&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://hackster.imgix.net/uploads/attachments/1279332/f0kdo3ekf73rjl0_3rwwb4nFw5.jpeg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt="">1 / 3</p><ul><li>The Serial CAN Bus Module included in the OBD-II CAN-BUS Dev kit is connected to the Wio Terminal UART interface via Grove cable</li><li>Connect the wires from the previous step to the Serial CAN Bus Module, connect red to CANH and black to CANL.</li></ul><h4 id="step-5-software-and-settings" tabindex="-1">Step 5: Software and Settings <a href="#toc-step-5--software-and-settings-4" id="toc-step-5--software-and-settings-4"></a> <a class="header-anchor" href="#step-5-software-and-settings" aria-label="Permalink to &quot;Step 5: Software and Settings &lt;a href=&quot;#toc-step-5--software-and-settings-4&quot; id=&quot;toc-step-5--software-and-settings-4&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://hackster.imgix.net/uploads/attachments/1279338/f07c1gtkf73rjpd_fXt2lSOIWu.jpeg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt=""></p><p>Here we need to make some settings for the serial can bus module.</p><p>Before we start, we need to download the code of this project. You can click to download <a href="https://github.com/Longan-Labs/OBD-II-Demo-x-Wio-Terminal" target="_blank" rel="noreferrer">Arduino Library</a>.</p><p>If you are using wio terminal for the first tme, you can check <a href="https://wiki.seeedstudio.com/Wio-Terminal-Getting-Started/" target="_blank" rel="noreferrer">wiki for wio terminal</a></p><p>First, we open the setting demo in the sketch, where we will set the mask and filter of the serial can bus module.</p><p>Then burning the setting demo to the wio terminal, open the serial monitor and enter a character at random to see whether the setting is successful or not.</p><p>After the setting is completed, burn the demo to the wio terminal and you can see the data on the screen.</p><h4 id="step-6-test-on-your-car" tabindex="-1">Step 6: Test on Your Car <a href="#toc-step-6--test-on-your-car-5" id="toc-step-6--test-on-your-car-5"></a> <a class="header-anchor" href="#step-6-test-on-your-car" aria-label="Permalink to &quot;Step 6: Test on Your Car &lt;a href=&quot;#toc-step-6--test-on-your-car-5&quot; id=&quot;toc-step-6--test-on-your-car-5&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://hackster.imgix.net/uploads/attachments/1279339/f2t1gtqkf73rlm1_57AaNjZTLs.jpeg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt="">1 / 3</p><p>Next, we need to go to the car and test it. You can find the OBD-II interface under the steering wheel, plug the connector into the OBD-II interface, turn on the wio terminal, and you can see the result.</p><h4 id="step-7-what-can-be-improved" tabindex="-1">Step 7: What Can Be Improved <a href="#toc-step-7--what-can-be-improved-6" id="toc-step-7--what-can-be-improved-6"></a> <a class="header-anchor" href="#step-7-what-can-be-improved" aria-label="Permalink to &quot;Step 7: What Can Be Improved &lt;a href=&quot;#toc-step-7--what-can-be-improved-6&quot; id=&quot;toc-step-7--what-can-be-improved-6&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Wio is a powerful main control board, we used quite a few functions in it. For example, Bluetooth, wi-wifi, etc.</p><p>Of course, you can also make a more beautiful interface. In short, you can play and enjoy the production process.</p><p>More CAN Bus gadgets: <a href="https://www.longan-labs.cc/" target="_blank" rel="noreferrer">Longan Labs Official Site</a></p><h3 id="schematics" tabindex="-1">Schematics <a class="header-anchor" href="#schematics" aria-label="Permalink to &quot;Schematics&quot;">​</a></h3><h4 id="schematics-of-serial-can-bus-module-in-the-dev-kit" tabindex="-1">Schematics of Serial CAN Bus Module in the Dev Kit <a class="header-anchor" href="#schematics-of-serial-can-bus-module-in-the-dev-kit" aria-label="Permalink to &quot;Schematics of Serial CAN Bus Module in the Dev Kit&quot;">​</a></h4><h3 id="code" tabindex="-1">Code <a class="header-anchor" href="#code" aria-label="Permalink to &quot;Code&quot;">​</a></h3><h4 id="arduino-library-for-the-demo-of-obd-ii-and-wio-terminal" tabindex="-1">Arduino Library for the demo of OBD-II and Wio Terminal <a class="header-anchor" href="#arduino-library-for-the-demo-of-obd-ii-and-wio-terminal" aria-label="Permalink to &quot;Arduino Library for the demo of OBD-II and Wio Terminal&quot;">​</a></h4><h4 id="longan-labs-obd-ii-demo-x-wio-terminal" tabindex="-1"><a href="https://github.com/Longan-Labs" target="_blank" rel="noreferrer">Longan-Labs</a> / <a href="https://github.com/Longan-Labs/OBD-II-Demo-x-Wio-Terminal" target="_blank" rel="noreferrer">OBD-II-Demo-x-Wio-Terminal</a> <a class="header-anchor" href="#longan-labs-obd-ii-demo-x-wio-terminal" aria-label="Permalink to &quot;[Longan-Labs](https://github.com/Longan-Labs) / [OBD-II-Demo-x-Wio-Terminal](https://github.com/Longan-Labs/OBD-II-Demo-x-Wio-Terminal)&quot;">​</a></h4><p><a href="https://github.com/Longan-Labs/OBD-II-Demo-x-Wio-Terminal/watchers" target="_blank" rel="noreferrer">12</a> <a href="https://github.com/Longan-Labs/OBD-II-Demo-x-Wio-Terminal/forks" target="_blank" rel="noreferrer">0</a></p><p>No description — <a href="https://github.com/Longan-Labs/OBD-II-Demo-x-Wio-Terminal#readme" target="_blank" rel="noreferrer">Read More</a></p><p>Latest commit to the <strong>master</strong> branch on 5-8-2021</p><p><a href="https://github.com/Longan-Labs/OBD-II-Demo-x-Wio-Terminal/archive/master.zip" target="_blank" rel="noreferrer">Download as zip</a></p><h3 id="credits" tabindex="-1">Credits <a class="header-anchor" href="#credits" aria-label="Permalink to &quot;Credits&quot;">​</a></h3>',55)])])}const u=e(i,[["render",n]]);export{m as __pageData,u as default};
